class Solution:
    def longestPrefix(self, s: str) -> str:
        n = len(s)
        failure = [0] * n
        k = 0
        for i in range(1, n):
            while k > 0 and s[k] != s[i]:
                k = failure[k - 1]
            if s[k] == s[i]:
                k += 1
            failure[i] = k
        return s[:failure[n - 1]]

