var longestPrefix = function(s) {
    const n = s.length;
    const failure = new Array(n).fill(0);
    let k = 0;
    for (let i = 1; i < n; i++) {
        while (k > 0 && s[k] !== s[i]) {
            k = failure[k - 1];
        }
        if (s[k] === s[i]) k++;
        failure[i] = k;
    }
    return s.slice(0, failure[n - 1]);
};
